import React, { useEffect, useState } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({ id: null, nombre: "" });
  const [productosFiltrados, setProductosFiltrados] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);

  useEffect(() => {
    obtenerCategorias();
    obtenerProductos();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    }
  };

  const filtrarProductos = (cat) => {
    setCategoriaActual(cat);
    const filtrados = productos.filter((p) => p.categoria_id === cat.id);
    setProductosFiltrados(filtrados);
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ id: null, nombre: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (cat) => {
    setCategoriaActual(cat);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.id}`,
          categoriaActual
        );
      } else {
        await axios.post("http://localhost:5000/api/categorias", categoriaActual);
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar esta categoría?")) {
      try {
        await axios.delete(`http://localhost:5000/api/categorias/${id}`);
        obtenerCategorias();
        if (categoriaActual.id === id) {
          setCategoriaActual({ id: null, nombre: "" });
          setProductosFiltrados([]);
        }
      } catch (error) {
        console.error("❌ Error al eliminar categoría:", error);
      }
    }
  };

  return (
    <div className="container mt-5 position-relative">
      <h2 className="fw-bold mb-4">Categorías</h2>

      {/* LISTA DE CATEGORÍAS */}
      <div className="row g-3">
        {categorias.map((cat) => (
          <div key={cat.id} className="col-md-4">
            <div
              className={`card shadow-sm p-3 position-relative ${
                categoriaActual.id === cat.id ? "border-primary" : ""
              }`}
            >
              <div onClick={() => filtrarProductos(cat)} style={{ cursor: "pointer" }}>
                <h5 className="card-title mb-2">{cat.nombre}</h5>
              </div>

              {/* BOTONES EDITAR Y ELIMINAR */}
              <div className="position-absolute top-2 end-2 d-flex gap-1">
                <button
                  className="btn btn-warning btn-sm"
                  onClick={() => abrirModalEditar(cat)}
                >
                  ✏️
                </button>
                <button
                  className="btn btn-danger btn-sm"
                  onClick={() => eliminarCategoria(cat.id)}
                >
                  🗑️
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* BOTÓN FLOTANTE NUEVA CATEGORÍA */}
      <button
        className="btn btn-success rounded-circle shadow-lg position-fixed"
        style={{ bottom: "30px", right: "30px", width: "60px", height: "60px", fontSize: "24px" }}
        onClick={abrirModalAgregar}
      >
        ➕
      </button>

      {/* PRODUCTOS FILTRADOS */}
      {productosFiltrados.length > 0 && (
        <div className="mt-5">
          <h4>Productos de {categoriaActual.nombre}</h4>
          <div className="table-responsive">
            <table className="table table-bordered text-center align-middle">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>Nombre</th>
                  <th>Descripción</th>
                  <th>Precio</th>
                  <th>Stock</th>
                </tr>
              </thead>
              <tbody>
                {productosFiltrados.map((p) => (
                  <tr key={p.ProductoID}>
                    <td>{p.ProductoID}</td>
                    <td>{p.Nombre}</td>
                    <td>{p.Descripcion}</td>
                    <td>${p.Precio}</td>
                    <td>{p.Stock}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* MODAL PARA AGREGAR/EDITAR CATEGORÍA */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4 shadow-lg">
              <div className="modal-header">
                <h5 className="modal-title fw-bold">
                  {modoEdicion ? "Editar Categoría" : "Agregar Categoría"}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <div className="modal-body">
                <form onSubmit={guardarCategoria}>
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      name="nombre"
                      value={categoriaActual.nombre}
                      onChange={(e) => setCategoriaActual({ ...categoriaActual, nombre: e.target.value })}
                      className="form-control"
                      required
                    />
                  </div>
                  <div className="text-end">
                    <button
                      type="button"
                      className="btn btn-secondary me-2"
                      onClick={() => setShowModal(false)}
                    >
                      Cancelar
                    </button>
                    <button type="submit" className="btn btn-primary">
                      {modoEdicion ? "Guardar Cambios" : "Agregar"}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
